        wire                                    fpga_mem_wr_en          = |wr_en;
        
        reg     [FPGA_MEM_WIDTH-1:0]            fpga_mem_wr_data;
        reg     [FPGA_MEM_WR_EN_WIDTH-1:0]      fpga_mem_bwe;
