                                                fpga_mem_wr_data[i*FPGA_MEM_WR_RESOLUTION+:FPGA_MEM_WR_RESOLUTION]      = {{(FPGA_MEM_ZERO_PADDING){1'b0}},wr_data[i*MEM_WR_RESOLUTION+:MEM_WR_RESOLUTION]};
                                end
