                .width_a                        (FPGA_MEM_WIDTH)                ,
                .width_byteena_a                (FPGA_MEM_WR_EN_WIDTH))
        fpga_mem (
                .address_a                      (adr)                           ,
                .clock0                         (clk)                           ,
                .data_a                         (fpga_mem_wr_data)              ,
                .wren_a                         (fpga_mem_wr_en)                ,
                .rden_a                         (1'b1)                          ,
                .q_a                            (fpga_mem_rd_data)              ,
                .aclr0                          (1'b0)                          ,
                .aclr1                          (1'b0)                          ,
                .address_b                      (1'b1)                          ,
                .addressstall_a                 (1'b0)                          ,
                .addressstall_b                 (1'b0)                          ,
                .byteena_a                      (fpga_mem_bwe)                  ,
                .byteena_b                      (1'b1)                          ,
                .clock1                         (1'b1)                          ,
                .clocken0                       (1'b1)                          ,
                .clocken1                       (1'b1)                          ,
                .clocken2                       (1'b1)                          ,
                .clocken3                       (1'b1)                          ,
                .data_b                         (1'b1)                          ,
                .eccstatus                      ()                              ,
                .q_b                            ()                              ,
