        assign          rd_data[MEM_WIDTH-1:0]  = rd_en_delay[MEM_DELAY] ? rd_data_delay[MEM_DELAY-1][MEM_WIDTH-1:0] : rd_data_delay[MEM_DELAY][MEM_WIDTH-1:0];

