                                                        for (int i = 0; i < MEM_DEPTH-1; i = i + 1) begin
                                                                for (int j = 0; j < MEM_INIT_PROT_INST_NUM; j = j + 1) begin
                                                                        init_word[i][j*(MEM_INIT_VALUE_WIDTH/MEM_INIT_PROT_INST_NUM) +: MEM_INIT_VALUE_WIDTH/MEM_INIT_PROT_INST_NUM]    = i+1;
