                                                        end
                                                        
                                                end
                                                
                                        end
                                        else begin
                                        
                                                initial begin
                                                        init_word[MEM_DEPTH-1]={(MEM_INIT_VALUE_WIDTH){1'b0}};
                                                        for (int i = 0; i < MEM_DEPTH-1; i = i + 1) begin
                                                                init_word[i] = i;
                                                        end
                                                
                                                end
                                        
                                        end

