                                                                        for(int j = 0; j < MEM_WR_EN_WIDTH; j = j + 1)
                                                                                fpga_mem.mem_data[i][j*FPGA_MEM_WR_RESOLUTION+:FPGA_MEM_WR_RESOLUTION]  = {init_word[i][j*MEM_WR_RESOLUTION+:MEM_WR_RESOLUTION]};
