                .aclr1                          (1'b0)                          ,
                .address_b                      (1'b1)                          ,
                .addressstall_a                 (1'b0)                          ,
                .addressstall_b                 (1'b0)                          ,
                .byteena_a                      (fpga_mem_bwe)                  ,
                .byteena_b                      (1'b1)                          ,
                .clock1                         (1'b1)                          ,
                .clocken0                       (1'b1)                          ,
