module  hlp_pm_wrap_mem_sector7_shell_2048x72hlp_pm_apr_18 #(
                // Memory General Parameters
                parameter MEM_WIDTH                     = 42                                                                                                                            ,
                parameter MEM_DEPTH                     = 3086                                                                                                                          ,
                parameter MEM_WR_RESOLUTION             = MEM_WIDTH                                                                                                                     ,
                parameter MEM_WR_EN_WIDTH               = (MEM_WIDTH/MEM_WR_RESOLUTION)                                                                                                 ,
                parameter MEM_DELAY                     = 1                                                                                                                             ,
                parameter MEM_PST_EBB_SAMPLE            = 0                                                                                                                             ,
                parameter MEM_ADR_WIDTH                 = (MEM_DEPTH>1) ? $clog2(MEM_DEPTH) : 1                                                                                         ,
                parameter MEM_RM_WIDTH                  = `HLP_MEM_RM_WIDTH                                                                                                         ,
                parameter FROM_MEM_WIDTH                = MEM_WIDTH + 1                                                                                                                 ,
                parameter TO_MEM_WIDTH                  = 0+1+MEM_RM_WIDTH+1+1+MEM_WR_EN_WIDTH+MEM_ADR_WIDTH+MEM_WIDTH                                                                  ,                                       
                // FAST_CONFIG Parameters
                parameter MEM_INIT_TYPE                 = 1                                                                                                                             , // 1 - Const. Val. Init., 2 - LL, Other - No Init.
                parameter LL_INIT_OFFSET                = 1                                                                                                                             ,
                parameter LL_IS_LAST                    = 1                                                                                                                             , //LINA CHANGE
                parameter MEM_INIT_VALUE                = 0                                                                                                                             , 
                parameter MEM_INIT_VALUE_WIDTH          = $bits(MEM_INIT_VALUE)                                                                                                         ,
                parameter MEM_PROT_TYPE                 = 0                                                                                                                             ,
                parameter MEM_PROT_RESOLUTION           = MEM_WR_RESOLUTION                                                                                                             ,
                parameter MEM_PROT_INST_WIDTH           = (MEM_PROT_TYPE == 0) ? $clog2(MEM_PROT_RESOLUTION+$clog2(MEM_PROT_RESOLUTION)+1)+1 : 1                                        ,                                                                                                                               
                parameter MEM_INIT_PROT_INST_NUM        = MEM_INIT_VALUE_WIDTH/MEM_PROT_RESOLUTION                                                                                      ,    

                parameter       MEM_WIDTH_NO_SIG                        = MEM_INIT_VALUE_WIDTH                                                                                                  ,
                parameter       MEM_WR_RESOLUTION_NO_SIG                = MEM_WIDTH_NO_SIG                                                                                                      ,
                parameter       MEM_WR_RES_PROT_FRAGM                   = 1                                                                                                                     , // Memory Write Resolution Fragmentation for Protection.      
                parameter       MEM_WR_RESOLUTION_ZERO_PADDING          = (MEM_PROT_RESOLUTION * MEM_WR_RES_PROT_FRAGM) - MEM_WR_RESOLUTION_NO_SIG                                       , // Memory Write Resolution Zero Padding.
                parameter       MEM_PROT_INTERLV_LEVEL                  = 1                                                                                                                     , // Memory Protection Bits Interleaving Level: 1 - No Interleaving, 2 - Every 2 bits (grouping of even and odd bits), 3 - Every 3 bits and Etc.
                parameter       MEM_PROT_PER_GEN_INST                   = (MEM_PROT_RESOLUTION % MEM_PROT_INTERLV_LEVEL) ? ((MEM_PROT_RESOLUTION-(MEM_PROT_RESOLUTION % MEM_PROT_INTERLV_LEVEL))/MEM_PROT_INTERLV_LEVEL) + 1 : (MEM_PROT_RESOLUTION/MEM_PROT_INTERLV_LEVEL)     , // Memory Width per protection module.
                parameter       MEM_PROT_RESOLUTION_ZERO_PADDING        = (MEM_PROT_PER_GEN_INST * MEM_PROT_INTERLV_LEVEL) - MEM_PROT_RESOLUTION                                         , // Memory Protection Resolution Zero Padding.
                parameter       MEM_TOTAL_ZERO_PADDING                  = ((MEM_PROT_RESOLUTION_ZERO_PADDING * MEM_WR_RES_PROT_FRAGM) + MEM_WR_RESOLUTION_ZERO_PADDING) * MEM_WR_EN_WIDTH       , // Memory Total Zero Padding. 
                parameter       MEM_PROT_TOTAL_GEN_INST                 = MEM_PROT_INTERLV_LEVEL * MEM_WR_RES_PROT_FRAGM * MEM_WR_EN_WIDTH                                                      ,
                parameter       MEM_PROT_INST_WIDTH_NO_SIG              = (MEM_PROT_TYPE == 0) ? $clog2(MEM_PROT_PER_GEN_INST+$clog2(MEM_PROT_PER_GEN_INST)+1)+1 : (MEM_PROT_TYPE == 1) ? 1 : 0 , // Data Integrity signature width for a single chunk of protected data
                parameter       MEM_PROT_TOTAL_WIDTH                    = MEM_PROT_TOTAL_GEN_INST * MEM_PROT_INST_WIDTH_NO_SIG                                                                         , // Total width of the Data Integrity signatures in Memory line.


                // FPGA Memory Parameters
                parameter FPGA_MEM_ZERO_PADDING         = (8 - (MEM_WR_RESOLUTION % 8)) % 8                                                                                             ,
                parameter FPGA_MEM_WR_RESOLUTION        = MEM_WR_RESOLUTION + FPGA_MEM_ZERO_PADDING                                                                                     ,
                parameter FPGA_MEM_WIDTH                = MEM_WR_EN_WIDTH*(FPGA_MEM_WR_RESOLUTION)                                                                                      ,
                parameter FPGA_MEM_WR_EN_WIDTH          = FPGA_MEM_WIDTH/8                                                                                                              
                // DFx Memory Parameters
               ,
                parameter MSWT_MODE                     = 0                                                                             ,
                parameter BYPASS_CLK_MUX                = 0                                                                             ,                
                parameter BYPASS_AFD_SYNC               = 1                                                                             ,
                parameter BYPASS_RST_B_SYNC             = 1                                                                             ,
                parameter BYPASS_MBIST_EN_SYNC          = 0                                                                             ,
                parameter WRAPPER_REDROW_ENABLE         = 0                                                                             ,
                parameter WRAPPER_COL_REPAIR            = 1                                                                             ,
                parameter NFUSEMISC_SRAM                = 20                                                                            ,
                parameter PWR_MGMT_IN_SIZE              = 6                                                                             ,                
                parameter NFUSERED_SRAM                 = $clog2(MEM_WIDTH) + 1                                                         ,
                parameter TOTAL_MEMORY_INSTANCE         = 1                                                       
)(
        // Memory General Interface
        input  logic                                                 clk                             ,
        input  logic         [  TO_MEM_WIDTH-1:0]                    wrap_shell_to_mem               ,
        output  wire    [FROM_MEM_WIDTH-1:0]                    wrap_shell_from_mem             
        // Memory DFx Interface 
       ,  
        input                                                   fary_output_reset               ,
        input                                                   fary_isolation_control_in       ,
        input                                 [1:0]             fary_ffuse_sram_sleep           ,        
        input                                                   fsta_dfxact_afd                 ,        
        input                                                   ip_reset_b                      ,  
        input                                                   post_mux_ctrl                   ,
        input                                                   fscan_clkungate                 ,           
        input                                                   fscan_ram_bypsel_sram           ,
        input                                                   fscan_ram_init_en               ,
        input                                                   fscan_ram_init_val              ,
        input                                                   fscan_ram_rdis_b                ,
        input                                                   fscan_ram_wdis_b                ,
        input           [PWR_MGMT_IN_SIZE-1:0]                  pwr_mgmt_in_sram                ,  
        input           [NFUSEMISC_SRAM-1:0]                    fary_ffuse_hduspsr_trim         ,     
        input           [NFUSEMISC_SRAM-1:0]                    fary_ffuse_hdusplr_trim         ,          
        input                                                   fary_pwren_b_sram               ,
        input                                                   fary_trigger_post_sram          , 
        output                                                  aary_post_pass_sram             ,
        output                                                  aary_post_complete_sram         ,
        output                                                  aary_pwren_b_sram               
        , input wire BIST_SETUP, input wire BIST_SETUP_ts1, 
        input wire BIST_SETUP_ts2, input wire to_interfaces_tck, 
        input wire mcp_bounding_to_en, input wire scan_to_en, 
        input wire memory_bypass_to_en, input wire BIST_CLEAR_BIRA, 
        input wire BIST_COLLAR_DIAG_EN, input wire BIST_COLLAR_BIRA_EN, 
        input wire PriorityColumn, input wire BIST_SHIFT_BIRA_COLLAR, 
        input wire CHECK_REPAIR_NEEDED, input wire MEM13_BIST_COLLAR_SI, 
        output wire BIST_SO, output wire BIST_GO, input wire ltest_to_en, 
        input wire BIST_WRITEENABLE, input wire BIST_READENABLE, 
        input wire BIST_CMP, input wire INCLUDE_MEM_RESULTS_REG, 
        input wire [1:0] BIST_COL_ADD, input wire [7:0] BIST_ROW_ADD, 
        input wire [0:0] BIST_BANK_ADD, input wire BIST_COLLAR_EN13, 
        input wire BIST_RUN_TO_COLLAR13, input wire BIST_ASYNC_RESET, 
        input wire BIST_TESTDATA_SELECT_TO_COLLAR, 
        input wire BIST_ON_TO_COLLAR, input wire [31:0] BIST_WRITE_DATA, 
        input wire [31:0] BIST_EXPECT_DATA, input wire BIST_SHIFT_COLLAR, 
        input wire BIST_COLLAR_SETUP, input wire BIST_CLEAR_DEFAULT, 
        input wire BIST_CLEAR, input wire BIST_COLLAR_OPSET_SELECT, 
        input wire BIST_COLLAR_HOLD, input wire FREEZE_STOP_ERROR, 
        input wire ERROR_CNT_ZERO, input wire MBISTPG_RESET_REG_SETUP2, 
        input wire bisr_shift_en_pd_vinf, input wire bisr_clk_pd_vinf, 
        input wire bisr_reset_pd_vinf, input wire ram_row_0_col_0_bisr_inst_SO, 
        output wire ram_row_0_col_0_bisr_inst_SO_ts1, 
        output wire bist_input_select_to_afd, input wire MBIST_Enable_Wrapper, 
        input wire fscan_clkungate_syn);

/*

Ralling Back due to MBIST and SV incompatibility - Hopedully will return to this code later

typedef struct packed{
        logic                                                   reset_n         ;
        logic                                                   rm_e            ;
        logic   [                         MEM_RM_WIDTH-1:0]     rm              ;
        logic                                                   rd_en           ;
        logic   [                      MEM_WR_EN_WIDTH-1:0]     wr_en           ;
        logic   [                        MEM_ADR_WIDTH-1:0]     adr             ;
        logic   [                            MEM_WIDTH-1:0]     wr_data         ;
} to_mem_t;

typedef struct packed{
        logic   [                            MEM_WIDTH-1:0]     rd_data         ;
        logic                                                   rd_valid        ;
} from_mem_t;

to_mem_t        to_mem_bus      ;
from_mem_t      from_mem_bus    ;

        // Disassembling the to_mem bus
        assign                          to_mem_bus      = wrap_shell_to_mem     ;
        wire                            reset_n         = to_mem_bus.reset_n    ;
        wire    [   MEM_RM_WIDTH-1:0]   mem_rm          = to_mem_bus.rm         ;
        wire                            mem_rm_e        = to_mem_bus.rm_e       ;
        wire                            rd_en           = to_mem_bus.rd_en      ;                                                       
        wire    [MEM_WR_EN_WIDTH-1:0]   wr_en           = to_mem_bus.wr_en      ;
        wire    [  MEM_ADR_WIDTH-1:0]   adr             = to_mem_bus.adr        ;
        wire    [      MEM_WIDTH-1:0]   wr_data         = to_mem_bus.wr_data    ;

        // Assembling the from_mem bus
        wire    [      MEM_WIDTH-1:0]   rd_data                                                                 ;
        wire                            rd_valid                                                                ;
        assign                          from_mem_bus.rd_data    = rd_data                                       ;
        assign                          from_mem_bus.rd_valid   = rd_valid                                      ;
        assign                          wrap_shell_from_mem     = from_mem_bus                                  ;

*/

        // Disassembling the to_mem bus
        
        wire [10:0] adr_ts1;
        wire [71:0] din;
        wire [27:0] ram_row_0_col_0_bisr_inst_Q;
        wire [8:0] ALL_SROW0_FUSE_ADD_REG, ALL_SROW1_FUSE_ADD_REG;
        wire wen, ren, ALL_SROW0_ALLOC_REG, ALL_SROW1_ALLOC_REG, 
             All_SCOL0_ALLOC_REG, 
             tessent_persistent_cell_BIST_INPUT_SELECT_INT_o;
        wire [6:0] All_SCOL0_FUSE_REG;
        wire                            reset_n         = wrap_shell_to_mem[2*MEM_WIDTH - MEM_PROT_TOTAL_WIDTH+MEM_ADR_WIDTH+MEM_WR_EN_WIDTH+3+MEM_RM_WIDTH      +:1                     ];
        //init_done
        wire                            mem_rm_e        = wrap_shell_to_mem[2*MEM_WIDTH - MEM_PROT_TOTAL_WIDTH+MEM_ADR_WIDTH+MEM_WR_EN_WIDTH+1+MEM_RM_WIDTH                   +:1                     ];
        wire    [   MEM_RM_WIDTH-1:0]   mem_rm          = wrap_shell_to_mem[2*MEM_WIDTH - MEM_PROT_TOTAL_WIDTH+MEM_ADR_WIDTH+MEM_WR_EN_WIDTH+1                   +:MEM_RM_WIDTH          ];
        wire                            rd_en           = wrap_shell_to_mem[2*MEM_WIDTH - MEM_PROT_TOTAL_WIDTH+MEM_ADR_WIDTH+MEM_WR_EN_WIDTH                     +:1                     ];
        wire    [MEM_WR_EN_WIDTH-1:0]   wr_en           = wrap_shell_to_mem[2*MEM_WIDTH - MEM_PROT_TOTAL_WIDTH+MEM_ADR_WIDTH                                     +:MEM_WR_EN_WIDTH       ];
        wire    [  MEM_ADR_WIDTH-1:0]   adr             = wrap_shell_to_mem[2*MEM_WIDTH - MEM_PROT_TOTAL_WIDTH                                                   +:MEM_ADR_WIDTH         ];

        //Next line added by SIVAKUMA for wr_data_orig
        wire    [      MEM_WIDTH-MEM_PROT_TOTAL_WIDTH-1:0]   wr_data_orig    = wrap_shell_to_mem[MEM_WIDTH                                                   +:MEM_WIDTH - MEM_PROT_TOTAL_WIDTH             ];

        wire    [      MEM_WIDTH-1:0]   wr_data         = wrap_shell_to_mem[0                                                           +:MEM_WIDTH             ];
                                                                  
        // Assembling the from_mem bus
        wire    [      MEM_WIDTH-1:0]   rd_data                                                                 ;         
        wire                            rd_valid                                                                ;                                                                       
        assign                          wrap_shell_from_mem[0]                  = rd_valid                      ;
        assign                          wrap_shell_from_mem[1+:MEM_WIDTH]       = rd_data                       ;

`ifdef DC
        `ifndef HLP_PM_ASIC_MEMS_EXCLUDE
                `define HLP_PM_ASIC_MEMS
        `endif
`endif

        // Memories Implementation
`ifdef HLP_PM_ASIC_MEMS
        
////////////////////////////////////////////////////////////////////////
//
//                              ASIC MEMORIES                                                                                                                   
//
////////////////////////////////////////////////////////////////////////



    // RAM Row Select

    wire    [1-1:0]                ram_row_sel;
    assign                    ram_row_sel[0]        = 1'b1;


    // RAM Address Decoder

    wire    [11-1:0]        ram_row_adr[1-1:0];
    assign                    ram_row_adr[0][11-1:0]    =  ram_row_sel[0] ? adr - 11'd0 : 11'd0;


    // RAM Read Enable Decoder

    wire    [1-1:0]        ram_row_rd_en;
    assign            ram_row_rd_en[0]        = ram_row_sel[0] ? rd_en : 1'b0;


    // Read Delay

    reg    [1-1:0]    rd_en_delay[MEM_DELAY:0];
    generate
            if (MEM_PST_EBB_SAMPLE == 1) begin: PST_EBB_SAMPLE_RD_EN_DELAY
                  logic [1-1:0]        ram_row_rd_en_s;
                  always_ff @(posedge clk) begin
                      ram_row_rd_en_s <= ram_row_rd_en;
                  end
                  assign  rd_en_delay[0][1-1:0] = ram_row_rd_en_s;
              end
              else begin: NO_PST_EBB_SAMPLE_RD_EN_DELAY
                  assign  rd_en_delay[0][1-1:0] = ram_row_rd_en;
              end
    endgenerate
    always_ff @(posedge clk)
            for (int i = 0; i <= (MEM_DELAY - 1); i = i + 1) begin
                rd_en_delay[i+1]        <= rd_en_delay[i];
            end
    logic    [1-1:0]        ram_row_num_rd_en_delay;
    always_ff @(posedge clk) begin
        if (|rd_en_delay[MEM_DELAY-1]) begin
            for (int i = 0; i < 1; i = i + 1) begin
                if (rd_en_delay[MEM_DELAY-1][i]) begin
                    ram_row_num_rd_en_delay[1-1:0]    <= i;
                end
            end
        end
    end


    // Write Data

    logic    [72-1:0]    wr_data_full;
    assign            wr_data_full    = wr_data;
    logic    [72-1:0]    ram_row_wr_data;
    always_comb begin
                ram_row_wr_data = 0;     // Overcome write_data width gap
        for (int i = 0; i < MEM_WR_EN_WIDTH; i = i + 1) begin
            ram_row_wr_data[i*(MEM_WR_RESOLUTION)+:MEM_WR_RESOLUTION]    = wr_data_full[i*MEM_WR_RESOLUTION+:MEM_WR_RESOLUTION];
        end
    end
    logic    [72-1:0]    ram_wr_data_col[1-1:0];
    always_comb begin
        for (int i = 0; i < 1; i = i + 1) begin
            ram_wr_data_col[i][72-1:0]        = ram_row_wr_data[i*72+:72];
        end
    end


    // Write Enable

    logic    [MEM_WR_EN_WIDTH-1:0]    wr_en_full;
    assign            wr_en_full    = wr_en;
    logic    [1-1:0]    ram_row_wr_en[1-1:0];
    always_comb begin
        ram_row_wr_en[0] = {1{1'b0}};
        ram_row_wr_en[0][1-1:0]    =  ram_row_sel[0] ? {{1{wr_en_full[0]}}} : 1'd0;
    end
    logic    [1-1:0]        ram_col_wr_en[1-1:0][1-1:0];
    assign        ram_col_wr_en[0][0]    = ram_row_wr_en[0][0*(1)+:1];


    // Read Data

    logic    [72-1:0]    ram_rd_data_col[1-1:0][1-1:0];
    logic    [72-1:0]    ram_rd_data_row;
    always_comb begin
        for (int i = 0; i < 1; i = i + 1) begin
            ram_rd_data_row[i*(72)+:72]        = ram_rd_data_col[ram_row_num_rd_en_delay[1-1:0]][i][72-1:0];
        end
    end
    logic    [1*MEM_WIDTH-1:0]    ram_rd_data_full;
    always_comb begin
        for (int i = 0; i < (MEM_WIDTH / MEM_WR_RESOLUTION); i = i + 1) begin
            ram_rd_data_full[i*MEM_WR_RESOLUTION+:MEM_WR_RESOLUTION]        = ram_rd_data_row[i*(MEM_WR_RESOLUTION+0)+:MEM_WR_RESOLUTION];
        end
    end
    logic    [MEM_WIDTH-1:0]    rd_data_int;
    always_comb begin
        rd_data_int[MEM_WIDTH-1:0]    =    ram_rd_data_full[MEM_WIDTH-1:0];
    end
    assign        rd_data        = rd_data_int;
    assign          rd_valid        = |rd_en_delay[MEM_DELAY];


    // EBBs Instantiation

        wire                            ram_row_0_col_0_clk         = clk;
        wire    [11-1:0]       ram_row_0_col_0_adr         = ram_row_adr[0][11-1:0];
        wire                            ram_row_0_col_0_ren         = ram_row_rd_en[0];
        wire                            ram_row_0_col_0_wen         = |ram_col_wr_en[0][0];
        wire    [72-1:0]      ram_row_0_col_0_data_in     = ram_wr_data_col[0][72-1:0];
        wire    [72-1:0]      ram_row_0_col_0_data_out;
        //wire    [1:0]                   ram_row_0_col_0_mc00b       = mem_rm_e ? mem_rm[1:0] : fary_ffuse_trim_sram[1:0];                      
        //clc wire    [NFUSEMISC_SRAM-1:0]      fary_ffuse_trim_sram = fary_ffuse_hduspsr_trim;
        wire                            ram_row_0_col_0_vss         = 1'b0;
                      
        hlp_ip783hdspsr2048x72m4b2s0c1r2p3d0a2_mem_wrapper #(
                                           )
        ram_row_0_col_0 (
                    //------------------------------------------------------------
                    // Functional Interfaces
                    //------------------------------------------------------------
                     .clk                 (ram_row_0_col_0_clk),
                     .ren                 (ren),
                     .wen                 (wen),
                     .adr                 (adr_ts1),
                     .din                 (din),
                     .q                   (ram_row_0_col_0_data_out),
                   //-------------------------------------------------------------
                   // Power Management Interfaces
                   //-------------------------------------------------------------           
        //            .PWR_MGMT_IN                       ({pwr_mgmt_in_sram[PWR_MGMT_IN_SIZE-1:1], ram_fary_pwren_b[0]}),
        //              .PWR_MGMT_OUT                     (ram_aary_pwren_b[0]),
                     .async_rst           (1'b0),
                     .fastsleep           (1'b0),
                     .deepsleep           (1'b0),
                     .sbc                 (2'b00),
                     .shutoff             (1'b0),
                     
                      `ifndef INTEL_NO_PWR_PINS
                      `ifdef INTC_ADD_VSS
                        .vss              (ram_row_0_col_0_vss),
                      `endif
                        .vddp             (1'b1),
                      `endif
                   //-------------------------------------------------------------
                   // DFx Interfaces
                   //-------------------------------------------------------------           
                  // .OUTPUT_RESET                        (fary_output_reset),
                   //-------------------------------------------------------------
                   // Fuse Interfaces
                   //-------------------------------------------------------------           
                   //  .TRIM_FUSE_IN                  ({fary_ffuse_trim_sram[NFUSEMISC_SRAM-1:2]}),
                     .mce                 (fary_ffuse_hduspsr_trim[5]),         // trim[5]
                     .stbyp               (fary_ffuse_hduspsr_trim[4]),     // trim[4]
                     .rmce                (fary_ffuse_hduspsr_trim[3:0]),       //trim[3:0]
                     .wmce                (fary_ffuse_hduspsr_trim[14:13]),       //trim[14:13]
                     .wpulse              (fary_ffuse_hduspsr_trim[12:11]),   //trim[12:11]
                     .wa_disable          (fary_ffuse_hduspsr_trim[10]), //trim[10]
                     .wa                  (fary_ffuse_hduspsr_trim[19:17]),           //trim[19:17]
                     .ra                  (fary_ffuse_hduspsr_trim[16:15]),           //trim[16:15]
        
                   //-------------------------------------------------------------
                   // Bist Interfaces
                   //-------------------------------------------------------------           
                   //  .BIST_CLK_IN                   (1'b0),
                   //  .BIST_ADDR_IN                  ('0),
                   //  .BIST_WR_EN_IN                 (1'b0),
                   //  .BIST_RD_EN_IN                 (1'b0),
                   //  .BIST_WR_DATA_IN               ('0),
                   //  .BIST_ENABLE                   (1'b0),
                          //-------------------------------------------------------------
                    // Scan Interfaces
                    //-------------------------------------------------------------           
                  //  .FSCAN_RAM_RDIS_B                 (fscan_ram_rdis_b),
                  //  .FSCAN_RAM_WDIS_B                 (fscan_ram_wdis_b),         
                  //  .FSCAN_RAM_BYPSEL                 (fscan_ram_bypsel_sram),
                //          .FSCAN_RAM_INIT_EN                (fscan_ram_init_en),
                  //  .FSCAN_RAM_INIT_VAL               (fscan_ram_init_val),
                  //  .FSCAN_CLKUNGATE                  (fscan_clkungate),
                      //-------------------------------------------------------------
                // Memory Repair inputs
                //-------------------------------------------------------------         
                    //.IP_RESET_B                        (IP_RESET_B_SYNC),
                    //.SLEEP_FUSE_IN                     (fary_ffuse_sram_sleep),
                    .col_repair_in                     ({
                                 5'b00000, ram_row_0_col_0_bisr_inst_Q[27:20]}),
                    .row_repair_in                     ({3'b000, 
                                 ram_row_0_col_0_bisr_inst_Q[19:10], 3'b000, 
                                 ram_row_0_col_0_bisr_inst_Q[9:0]}),  
                    .global_rrow_en_in                 ('0),  
                    //.ARRAY_FREEZE                      (ARRAY_FREEZE_SYNC),
                    .isolation_control_in              (fary_isolation_control_in),
                    //.WRAPPER_CLK_EN                    (1'b1)
                    .dpslp_or_shutoffout               (),
                    .shutoffout                        ()
        );// hlp_ip783hdspsr2048x72m4b2s0c1r2p3d0a2_mem_wrapper
        
        assign          ram_rd_data_col[0][0]      = ram_row_0_col_0_data_out;
           

// DFX output concatination 
                
`elsif HLP_FPGA_MEMS

////////////////////////////////////////////////////////////////////////
