        output wire bist_input_select_to_afd, input wire MBIST_Enable_Wrapper, 
        input wire fscan_clkungate_syn);

/*

Ralling Back due to MBIST and SV incompatibility - Hopedully will return to this code later

typedef struct packed{
        logic                                                   reset_n         ;
        logic                                                   rm_e            ;
        logic   [                         MEM_RM_WIDTH-1:0]     rm              ;
        logic                                                   rd_en           ;
        logic   [                      MEM_WR_EN_WIDTH-1:0]     wr_en           ;
        logic   [                        MEM_ADR_WIDTH-1:0]     adr             ;
        logic   [                            MEM_WIDTH-1:0]     wr_data         ;
} to_mem_t;

typedef struct packed{
        logic   [                            MEM_WIDTH-1:0]     rd_data         ;
        logic                                                   rd_valid        ;
} from_mem_t;

to_mem_t        to_mem_bus      ;
from_mem_t      from_mem_bus    ;

        // Disassembling the to_mem bus
        assign                          to_mem_bus      = wrap_shell_to_mem     ;
        wire                            reset_n         = to_mem_bus.reset_n    ;
        wire    [   MEM_RM_WIDTH-1:0]   mem_rm          = to_mem_bus.rm         ;
        wire                            mem_rm_e        = to_mem_bus.rm_e       ;
        wire                            rd_en           = to_mem_bus.rd_en      ;                                                       
        wire    [MEM_WR_EN_WIDTH-1:0]   wr_en           = to_mem_bus.wr_en      ;
        wire    [  MEM_ADR_WIDTH-1:0]   adr             = to_mem_bus.adr        ;
        wire    [      MEM_WIDTH-1:0]   wr_data         = to_mem_bus.wr_data    ;

        // Assembling the from_mem bus
        wire    [      MEM_WIDTH-1:0]   rd_data                                                                 ;
        wire                            rd_valid                                                                ;
        assign                          from_mem_bus.rd_data    = rd_data                                       ;
        assign                          from_mem_bus.rd_valid   = rd_valid                                      ;
        assign                          wrap_shell_from_mem     = from_mem_bus                                  ;

*/

        // Disassembling the to_mem bus
        
        wire [10:0] adr_ts1;
        wire [71:0] din;
        wire [27:0] ram_row_0_col_0_bisr_inst_Q;
        wire [8:0] ALL_SROW0_FUSE_ADD_REG, ALL_SROW1_FUSE_ADD_REG;
        wire wen, ren, ALL_SROW0_ALLOC_REG, ALL_SROW1_ALLOC_REG, 
             All_SCOL0_ALLOC_REG, 
             tessent_persistent_cell_BIST_INPUT_SELECT_INT_o;
        wire [6:0] All_SCOL0_FUSE_REG;
        wire                            reset_n         = wrap_shell_to_mem[2*MEM_WIDTH - MEM_PROT_TOTAL_WIDTH+MEM_ADR_WIDTH+MEM_WR_EN_WIDTH+3+MEM_RM_WIDTH      +:1                     ];
        //init_done
        wire                            mem_rm_e        = wrap_shell_to_mem[2*MEM_WIDTH - MEM_PROT_TOTAL_WIDTH+MEM_ADR_WIDTH+MEM_WR_EN_WIDTH+1+MEM_RM_WIDTH                   +:1                     ];
        wire    [   MEM_RM_WIDTH-1:0]   mem_rm          = wrap_shell_to_mem[2*MEM_WIDTH - MEM_PROT_TOTAL_WIDTH+MEM_ADR_WIDTH+MEM_WR_EN_WIDTH+1                   +:MEM_RM_WIDTH          ];
        wire                            rd_en           = wrap_shell_to_mem[2*MEM_WIDTH - MEM_PROT_TOTAL_WIDTH+MEM_ADR_WIDTH+MEM_WR_EN_WIDTH                     +:1                     ];
        wire    [MEM_WR_EN_WIDTH-1:0]   wr_en           = wrap_shell_to_mem[2*MEM_WIDTH - MEM_PROT_TOTAL_WIDTH+MEM_ADR_WIDTH                                     +:MEM_WR_EN_WIDTH       ];
        wire    [  MEM_ADR_WIDTH-1:0]   adr             = wrap_shell_to_mem[2*MEM_WIDTH - MEM_PROT_TOTAL_WIDTH                                                   +:MEM_ADR_WIDTH         ];

        //Next line added by SIVAKUMA for wr_data_orig
        wire    [      MEM_WIDTH-MEM_PROT_TOTAL_WIDTH-1:0]   wr_data_orig    = wrap_shell_to_mem[MEM_WIDTH                                                   +:MEM_WIDTH - MEM_PROT_TOTAL_WIDTH             ];

        wire    [      MEM_WIDTH-1:0]   wr_data         = wrap_shell_to_mem[0                                                           +:MEM_WIDTH             ];
                                                                  
        // Assembling the from_mem bus
        wire    [      MEM_WIDTH-1:0]   rd_data                                                                 ;         
        wire                            rd_valid                                                                ;                                                                       
        assign                          wrap_shell_from_mem[0]                  = rd_valid                      ;
        assign                          wrap_shell_from_mem[1+:MEM_WIDTH]       = rd_data                       ;

`ifdef DC
        `ifndef HLP_PM_ASIC_MEMS_EXCLUDE
                `define HLP_PM_ASIC_MEMS
        `endif
`endif

        // Memories Implementation
`ifdef HLP_PM_ASIC_MEMS
        
////////////////////////////////////////////////////////////////////////
//
//                              ASIC MEMORIES                                                                                                                   
//
////////////////////////////////////////////////////////////////////////



    // RAM Row Select

    wire    [1-1:0]                ram_row_sel;
    assign                    ram_row_sel[0]        = 1'b1;


    // RAM Address Decoder

    wire    [11-1:0]        ram_row_adr[1-1:0];
    assign                    ram_row_adr[0][11-1:0]    =  ram_row_sel[0] ? adr - 11'd0 : 11'd0;


    // RAM Read Enable Decoder

    wire    [1-1:0]        ram_row_rd_en;
    assign            ram_row_rd_en[0]        = ram_row_sel[0] ? rd_en : 1'b0;


    // Read Delay

    reg    [1-1:0]    rd_en_delay[MEM_DELAY:0];
    generate
            if (MEM_PST_EBB_SAMPLE == 1) begin: PST_EBB_SAMPLE_RD_EN_DELAY
                  logic [1-1:0]        ram_row_rd_en_s;
                  always_ff @(posedge clk) begin
                      ram_row_rd_en_s <= ram_row_rd_en;
                  end
                  assign  rd_en_delay[0][1-1:0] = ram_row_rd_en_s;
              end
              else begin: NO_PST_EBB_SAMPLE_RD_EN_DELAY
                  assign  rd_en_delay[0][1-1:0] = ram_row_rd_en;
              end
    endgenerate
    always_ff @(posedge clk)
            for (int i = 0; i <= (MEM_DELAY - 1); i = i + 1) begin
                rd_en_delay[i+1]        <= rd_en_delay[i];
            end
    logic    [1-1:0]        ram_row_num_rd_en_delay;
    always_ff @(posedge clk) begin
        if (|rd_en_delay[MEM_DELAY-1]) begin
            for (int i = 0; i < 1; i = i + 1) begin
                if (rd_en_delay[MEM_DELAY-1][i]) begin
                    ram_row_num_rd_en_delay[1-1:0]    <= i;
                end
            end
        end
    end


    // Write Data

    logic    [72-1:0]    wr_data_full;
    assign            wr_data_full    = wr_data;
    logic    [72-1:0]    ram_row_wr_data;
    always_comb begin
                ram_row_wr_data = 0;     // Overcome write_data width gap
        for (int i = 0; i < MEM_WR_EN_WIDTH; i = i + 1) begin
            ram_row_wr_data[i*(MEM_WR_RESOLUTION)+:MEM_WR_RESOLUTION]    = wr_data_full[i*MEM_WR_RESOLUTION+:MEM_WR_RESOLUTION];
        end
    end
    logic    [72-1:0]    ram_wr_data_col[1-1:0];
    always_comb begin
        for (int i = 0; i < 1; i = i + 1) begin
            ram_wr_data_col[i][72-1:0]        = ram_row_wr_data[i*72+:72];
        end
    end


    // Write Enable

    logic    [MEM_WR_EN_WIDTH-1:0]    wr_en_full;
    assign            wr_en_full    = wr_en;
    logic    [1-1:0]    ram_row_wr_en[1-1:0];
    always_comb begin
        ram_row_wr_en[0] = {1{1'b0}};
        ram_row_wr_en[0][1-1:0]    =  ram_row_sel[0] ? {{1{wr_en_full[0]}}} : 1'd0;
    end
    logic    [1-1:0]        ram_col_wr_en[1-1:0][1-1:0];
    assign        ram_col_wr_en[0][0]    = ram_row_wr_en[0][0*(1)+:1];


    // Read Data

    logic    [72-1:0]    ram_rd_data_col[1-1:0][1-1:0];
    logic    [72-1:0]    ram_rd_data_row;
    always_comb begin
        for (int i = 0; i < 1; i = i + 1) begin
            ram_rd_data_row[i*(72)+:72]        = ram_rd_data_col[ram_row_num_rd_en_delay[1-1:0]][i][72-1:0];
        end
    end
    logic    [1*MEM_WIDTH-1:0]    ram_rd_data_full;
    always_comb begin
        for (int i = 0; i < (MEM_WIDTH / MEM_WR_RESOLUTION); i = i + 1) begin
            ram_rd_data_full[i*MEM_WR_RESOLUTION+:MEM_WR_RESOLUTION]        = ram_rd_data_row[i*(MEM_WR_RESOLUTION+0)+:MEM_WR_RESOLUTION];
        end
    end
    logic    [MEM_WIDTH-1:0]    rd_data_int;
    always_comb begin
        rd_data_int[MEM_WIDTH-1:0]    =    ram_rd_data_full[MEM_WIDTH-1:0];
    end
    assign        rd_data        = rd_data_int;
    assign          rd_valid        = |rd_en_delay[MEM_DELAY];


    // EBBs Instantiation

        wire                            ram_row_0_col_0_clk         = clk;
        wire    [11-1:0]       ram_row_0_col_0_adr         = ram_row_adr[0][11-1:0];
        wire                            ram_row_0_col_0_ren         = ram_row_rd_en[0];
        wire                            ram_row_0_col_0_wen         = |ram_col_wr_en[0][0];
        wire    [72-1:0]      ram_row_0_col_0_data_in     = ram_wr_data_col[0][72-1:0];
        wire    [72-1:0]      ram_row_0_col_0_data_out;
        //wire    [1:0]                   ram_row_0_col_0_mc00b       = mem_rm_e ? mem_rm[1:0] : fary_ffuse_trim_sram[1:0];                      
        //clc wire    [NFUSEMISC_SRAM-1:0]      fary_ffuse_trim_sram = fary_ffuse_hduspsr_trim;
        wire                            ram_row_0_col_0_vss         = 1'b0;
                      
        hlp_ip783hdspsr2048x72m4b2s0c1r2p3d0a2_mem_wrapper #(
                                           )
        ram_row_0_col_0 (
                    //------------------------------------------------------------
                    // Functional Interfaces
                    //------------------------------------------------------------
                     .clk                 (ram_row_0_col_0_clk),
                     .ren                 (ren),
                     .wen                 (wen),
                     .adr                 (adr_ts1),
                     .din                 (din),
                     .q                   (ram_row_0_col_0_data_out),
                   //-------------------------------------------------------------
                   // Power Management Interfaces
                   //-------------------------------------------------------------           
        //            .PWR_MGMT_IN                       ({pwr_mgmt_in_sram[PWR_MGMT_IN_SIZE-1:1], ram_fary_pwren_b[0]}),
        //              .PWR_MGMT_OUT                     (ram_aary_pwren_b[0]),
                     .async_rst           (1'b0),
