                     .ra                  (fary_ffuse_hduspsr_trim[16:15]),           //trim[16:15]
        
                   //-------------------------------------------------------------
                   // Bist Interfaces
                   //-------------------------------------------------------------           
                   //  .BIST_CLK_IN                   (1'b0),
                   //  .BIST_ADDR_IN                  ('0),
                   //  .BIST_WR_EN_IN                 (1'b0),
                   //  .BIST_RD_EN_IN                 (1'b0),
                   //  .BIST_WR_DATA_IN               ('0),
                   //  .BIST_ENABLE                   (1'b0),
                          //-------------------------------------------------------------
                    // Scan Interfaces
                    //-------------------------------------------------------------           
                  //  .FSCAN_RAM_RDIS_B                 (fscan_ram_rdis_b),
                  //  .FSCAN_RAM_WDIS_B                 (fscan_ram_wdis_b),         
                  //  .FSCAN_RAM_BYPSEL                 (fscan_ram_bypsel_sram),
